mapper.update:
update
    rdp_ticket_process
set
    stage_context=#{context}
WHERE
    id = #{id}

update
    rdp_ticket_process
set
    process_status = #{status}
where ticket_id = #{ticketId}
and process_status = 'INIT'

update
    rdp_ticket_process
set
    process_status = #{status}
where ticket_id = #{ticketId}
  and ticket_stage = #{stage,javaType=com.clougence.clouddm.console.web.dal.enumeration.RdpTicketStage}

update
    rdp_ticket_process
set
    process_status = #{status},stage_context = #{context}
    ,finish_time = now()
where id = #{id}
